using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationMetrics
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationMetrics _evaluationMetrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 0);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = BuildPipeline();

        // With a small dataset we train on the full set and evaluate against it
        // to surface basic sanity metrics. In production, use a proper train/test split.
        _model = pipeline.Fit(dataView);

        var predictions = _model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);
        _evaluationMetrics = new EvaluationMetrics
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction
        };

        // Extract ordered label names so we can map Score[] indices to categories
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        predictions.Schema["Score"]
            .GetSlotNames(ref labelBuffer);
        _categoryLabels = labelBuffer.DenseValues()
            .Select(v => v.ToString())
            .ToArray();

        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public EvaluationMetrics GetEvaluationMetrics() => _evaluationMetrics;

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    private IEstimator<ITransformer> BuildPipeline()
    {
        // Combine Subject + Description into a single text feature, featurize it,
        // then concatenate with the numeric Priority column.
        return _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly TicketClassifierService _classifierService;

    public TicketClassifierController(TicketClassifierService classifierService)
    {
        _classifierService = classifierService;
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("predict")]
    public ActionResult<TicketPredictionResponse> Predict([FromBody] TicketRequest request)
    {
        var result = _classifierService.Predict(request);
        return Ok(result);
    }

    /// <summary>
    /// Returns model evaluation metrics computed at startup.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        return Ok(_classifierService.GetEvaluationMetrics());
    }
}

