namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly TicketClassifierService _classifierService;

    public TicketClassifierController(TicketClassifierService classifierService)
    {
        _classifierService = classifierService;
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("predict")]
    public ActionResult<TicketPredictionResponse> Predict([FromBody] TicketRequest request)
    {
        var result = _classifierService.Predict(request);
        return Ok(result);
    }

    /// <summary>
    /// Returns model evaluation metrics computed at startup.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        return Ok(_classifierService.GetEvaluationMetrics());
    }
}

